local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxShopCtrl:LxBaseCtrl
local LxShopCtrl = classX("LxShopCtrl", LxBaseCtrl)

function LxShopCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxShopCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end


function LxShopCtrl:OnShopBuyResult(shopObj, things,use)
    ShowSysMsg(I18nText(4215))
    FireEvent(EventNames.SHOP_BUY_RESULT, shopObj, things)
    if(shopObj)then
        if(shopObj.shopRefId == 401 or shopObj.shopRefId == 601)then

            return
        end
    end
    if not use then
        things.windowType = 1
        if(shopObj.shopRefId == 1002 or shopObj.shopRefId == 1003)then
            things.windowType = 0
        end
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Shop, things)
    end
end


---@param refId number 固定商店配置表 refId
function LxShopCtrl:CheckShopConditions(refId)
    local ref = GameTable.StoreFixedRef[refId]
    if not ref then
        if LOG_INFO_ENABLED then
            printError("StoreFixedRef", "不存在商店id="..tostring(refId))
        end
        return true
    end
    local funcOpenCtrl = CtrlCenter.FuncOpen
    local open = funcOpenCtrl:CheckConditions(ref.openCondition)
    if open and funcOpenCtrl:CheckConditions(ref.closeCondition) then
        open = false
    end
    return open
end


---@param refId number 固定商店配置表 refId
function LxShopCtrl:CheckShopShow(refId)
    local ref = GameTable.StoreFixedRef[refId]
    if not ref then
        if LOG_INFO_ENABLED then
            printError("StoreFixedRef", "不存在商店id="..tostring(refId))
        end
        return true
    end
    if ref.showNoOpen == 1 then return true end
    return self:CheckShopConditions(refId)
end

--- 购买商品逻辑
---@param info table<goodsInfo:LxGoodsInfo,shopRef:V_ShopPublicRef,goodsRef:V_ShopFixedRef>
function LxShopCtrl:BuyShopItem(info)
    ---@type LxGoodsInfo
    local goodsInfo = info.goodsInfo
    if not goodsInfo then return end

    local shopRef = info.shopRef
    if not shopRef then return end

    local goodRef = info.goodRef
    if not goodRef then return end

    ShowPanel(UiNames.ShopBuy, {
        goodsInfo = goodsInfo,
        shopRef = shopRef,
        goodsRef = goodRef,
    })
end

--- 商店总红点
function LxShopCtrl:CheckShopAllRed()
    local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.Shop)
    if not isOpen then
        return 0
    end
    local typeTbls = GameTable.ShopStoreTypeRef
    for _, v in pairs(typeTbls) do
        if string.isempty(v.functionMgrRefId) or CtrlCenter.FuncOpen:IsFuncShow(v.functionMgrRefId) then
            if self:CheckShopRedByStoreType(v.refId) then
                return 1
            end
        end
    end
    return 0
end

---@param storeType number 根据商店类型来判断是否存在红点
function LxShopCtrl:CheckShopRedByStoreType(storeType)
    local shopTbls = GameTable.ShopPublicRef
    for _, v in pairs(shopTbls) do
        if v.storeType == storeType and (string.isempty(v.functionMgrRefId) or CtrlCenter.FuncOpen:IsFuncShow(v.functionMgrRefId)) then
            if self:CheckShopRedByRefId(v.refId, v.shopType) then
                return true
            end
        end
    end
    return false
end

--- 根据refId 商店通用配置表的商店唯一编号 判断是否存在红点 目前商店红点只需要判断是否是免费的
---@param refId number 商店唯一编号
---@param shopType number 商店类型
function LxShopCtrl:CheckShopRedByRefId(refId, shopType)
    local refTbl = shopType == 1 and GameTable.StoreFixedRef or GameTable.StoreRandomRef
    for _, v in pairs(refTbl) do
        if v.priceType == ShopPriceType.FREE then
            local buyLimitData = string.split(v.buyLimit,"=")
            local buyNum = checknumber(buyLimitData[2])
            ---@type LxShopObj
            local shopInfo = ModuleCenter.Shop:GetShopObj(refId)
            if shopInfo then
                for _, v2 in ipairs(shopInfo.goodsInfo) do
                    if v.refId == v2.goodsRefId and v2.buyCount < buyNum then
                        return true
                    end
                end
            end
        end
    end
    return false
end

--- 对应的商店是否有免费刷新
function LxShopCtrl:CheckShopIsFreeRefresh(refId)
    ---@type LxShopObj
    local shopInfo = ModuleCenter.Shop:GetShopObj(refId)
    if shopInfo then
        return shopInfo.freeCount > 0
    end
    return false
end


function LxShopCtrl:GetConditionTipsList(conditionStrList)
    local ret = {}
    local tipsList = {}
    for k,v in ipairs(conditionStrList or {}) do
        local arr = string.split(v,"=")
        if arr and #arr >= 2 then
            local str, tips = self:GetConditionTips(arr)
            if not string.isempty(str) then
                table.insert(ret, str)
            end
            if not string.isempty(tips) then
                table.insert(tipsList, tips)
            end
        end
    end
    return ret, tipsList
end

function LxShopCtrl:GetConditionTips(conditionParams)
    local cdtTextRef = GameTable.ShopConditionTextRef
    local conditionType = tonumber(conditionParams[1])
    local ref = cdtTextRef[conditionType]
    if ref then
        if conditionType == 1 then
            local cdtLv = tonumber(conditionParams[3]) or 0
            return I18nText(ref.conditionText, cdtLv), I18nText(ref.conditionTextTip, cdtLv)
        else
            local cdtLv = tonumber(conditionParams[2]) or 0
            return I18nText(ref.conditionText, cdtLv), I18nText(ref.conditionTextTip, cdtLv)
        end
    end

end
--- 根据对应的商店id 判断 该商店是否开启
function LxShopCtrl:CheckShopIsOpenById(refId)
    local lv = ModuleCenter.Building:GetBuildingLvl(self._buildingRefId)
    if lv <= 0 then
        return false
    end
    local shopRef = GameTable.ShopPublicRef[refId]
    if shopRef then
        local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(shopRef.functionMgrRefId)
        return isOpen
    end
    return false
end
return LxShopCtrl